/// Default weight for bigrams not in the table.
pub const DEFAULT_WEIGHT: f32 = 1.0;

/// Look up the IDF weight for `key` in any sorted `(key, weight)` slice.
///
/// Falls back to [`DEFAULT_WEIGHT`] when `key` is absent from the table.
/// The caller must ensure the slice is sorted ascending by key.
#[must_use]
#[inline]
pub fn lookup_weight(key: u16, weights: &[(u16, f32)]) -> f32 {
    weights
        .binary_search_by_key(&key, |&(k, _)| k)
        .ok()
        .map(|idx| weights[idx].1)
        .unwrap_or(DEFAULT_WEIGHT)
}

/// Look up the IDF weight of a bigram by binary search against [`BIGRAM_WEIGHTS`].
///
/// Returns `None` if the bigram is absent from the table.
#[must_use]
pub fn bigram_weight(bigram: u16) -> Option<f32> {
    BIGRAM_WEIGHTS
        .binary_search_by_key(&bigram, |&(k, _)| k)
        .ok()
        .map(|idx| BIGRAM_WEIGHTS[idx].1)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn table_is_sorted_ascending() {
        let keys: Vec<u16> = BIGRAM_WEIGHTS.iter().map(|&(k, _)| k).collect();
        let mut sorted = keys.clone();
        sorted.sort();
        assert_eq!(keys, sorted, "BIGRAM_WEIGHTS must be sorted ascending");
    }

    #[test]
    fn no_duplicate_keys() {
        let keys: Vec<u16> = BIGRAM_WEIGHTS.iter().map(|&(k, _)| k).collect();
        let unique: std::collections::HashSet<u16> = keys.iter().copied().collect();
        assert_eq!(
            keys.len(),
            unique.len(),
            "BIGRAM_WEIGHTS must not have duplicate keys"
        );
    }

    #[test]
    fn bigram_weight_lookup_works() {
        // If the table is non-empty, the first entry must be findable.
        if let Some(&(key, idf)) = BIGRAM_WEIGHTS.first() {
            assert_eq!(bigram_weight(key), Some(idf));
        }
    }

    #[test]
    fn default_weight_is_positive() {
        const { assert!(DEFAULT_WEIGHT > 0.0) };
    }
}
